Method.Source:
public static void post(
    Common  _record,
    TableId _tableId,
    NoYes _transferErrors,
    boolean _splitLargeJournal ,
    boolean _suppressClientMessages,
    str _callingFormName ,
    LedgerJournalEngine _ledgerJournalEngine ,
    boolean _skipIL_RU ,
    LedgerJournalCheckPostResults _results_RU ,
    boolean _progressBarHide )
{
    if(ETG_Parameters::find().ETGIsDimensionValidationRequired == NoYes::Yes)
    {
        DimensionAttributeSetItem   dimAttrSetItem;
        DimensionAttribute          dimAttribute;
        DimensionEnumeration        dimensionSetId;
        DimensionAttributeLevelValueAllView  dimensionAttributeLevelValueAllView;
        DefaultDimensionView                 defaultDimView;
        boolean                              isDimensionEmpty = false;
        LedgerJournalTrans                   ledgerJournalTransCheck;

        dimensionSetId = DimensionCache::getDimensionAttributeSetForLedger();

        while select LedgerDimension,OffsetLedgerDimension,DefaultDimension,Voucher,AccountType,OffsetAccountType from ledgerJournalTransCheck
            where ledgerJournalTransCheck.JournalNum    == LedgerJournalTrans::findRecId(_record.RecId,false).JournalNum
        {
            if(ledgerJournalTransCheck.AccountType == LedgerJournalACType::Ledger)
            {
                select firstonly RecId from dimAttrSetItem
                    where  dimAttrSetItem.DimensionAttributeSet == dimensionSetId
                join Name from dimAttribute
                    where dimAttribute.RecId == dimAttrSetItem.DimensionAttribute
                        && dimAttribute.Type != DimensionAttributeType::MainAccount
                notexists join dimensionAttributeLevelValueAllView
                    where dimensionAttributeLevelValueAllView.DimensionAttribute ==  dimAttribute.RecId
                    && dimensionAttributeLevelValueAllView.ValueCombinationRecId == ledgerJournalTransCheck.LedgerDimension;

                if(dimAttrSetItem)
                    isDimensionEmpty = true;
            }

            if(ledgerJournalTransCheck.OffsetAccountType == LedgerJournalACType::Ledger && !isDimensionEmpty)
            {
                select firstonly RecId from dimAttrSetItem
                    where  dimAttrSetItem.DimensionAttributeSet == dimensionSetId
                join Name from dimAttribute
                    where dimAttribute.RecId == dimAttrSetItem.DimensionAttribute
                        && dimAttribute.Type != DimensionAttributeType::MainAccount
                notexists join dimensionAttributeLevelValueAllView
                    where dimensionAttributeLevelValueAllView.DimensionAttribute ==  dimAttribute.RecId
                    && dimensionAttributeLevelValueAllView.ValueCombinationRecId == ledgerJournalTransCheck.OffsetLedgerDimension;

                if(dimAttrSetItem)
                    isDimensionEmpty = true;
            }

            if((ledgerJournalTransCheck.OffsetAccountType != LedgerJournalACType::Ledger || ledgerJournalTransCheck.AccountType != LedgerJournalACType::Ledger)
            && !isDimensionEmpty)
            {
                select firstonly RecId from dimAttrSetItem
                    where  dimAttrSetItem.DimensionAttributeSet == dimensionSetId
                join Name from dimAttribute
                    where dimAttribute.RecId == dimAttrSetItem.DimensionAttribute
                        && dimAttribute.Type != DimensionAttributeType::MainAccount
                notexists join defaultDimView
                    where defaultDimView.Name ==  dimAttribute.Name
                        && defaultDimView.DefaultDimension == ledgerJournalTransCheck.DefaultDimension;

                if(dimAttrSetItem)
                    isDimensionEmpty = true;
            }

            if(isDimensionEmpty)
            {
                if(Box::yesNoAxaptaForm(strFmt('Few dimensions are not filled in the voucher - %1. Do you want to update? ',ledgerJournalTransCheck.Voucher), DialogButton::Yes) == DialogButton::Yes)
                {
                    throw warning('Update has been canceled');
                }
            }
        }
    }
    //CS Rajat Dubey 09/05/2025
    if(ETGACFParameters::find().MainAccountForGeneralJournal)
    {
        LedgerJournalTable      ledgerJournal;
        LedgerJournalTrans      ledgerJournalTrans,ledgerJournalTransLoc;
        MainAccountNum          ledgerMainAccountId, offsetMainAccountId;
        str                     mainAccountId = ETGACFParameters::find().MainAccountForGeneralJournal;
        int                     i = 0,j = 0;

        if(_tableId == tableNum(LedgerJournalTable))
        {
            ledgerJournal = _record;
        }
        else if(_tableId == tableNum(LedgerJournalTrans))
        {
            ledgerJournalTrans = _record;
            if(ledgerJournalTrans)
            {
                ledgerJournal = ledgerJournalTrans.ledgerJournalTable();
            }
        }
        while select * from ledgerJournalTransLoc
            where ledgerJournalTransLoc.JournalNum == ledgerJournal.JournalNum
        {
            ledgerMainAccountId = LedgerDimensionFacade::getMainAccountFromLedgerDimension(ledgerJournalTransLoc.LedgerDimension).MainAccountId;
            offsetMainAccountId = LedgerDimensionFacade::getMainAccountFromLedgerDimension(ledgerJournalTransLoc.OffsetLedgerDimension).MainAccountId;
            i = strScan(mainAccountId,ledgerMainAccountId,1,strLen(mainAccountId));
            j = strScan(mainAccountId,offsetMainAccountId,1,strLen(mainAccountId));

            if(i>0||j>0)
            {
                throw error(strFmt("@ETG_New:ManualJournalNotPermittedForMainAccount", ledgerJournalTransLoc.LineNum,ledgerJournalTransLoc.Voucher,ledgerMainAccountId,offsetMainAccountId));
            }
        }
    }
    //CE Rajat Dubey 09/05/2025

    next post(_record,_tableId,_transferErrors,_splitLargeJournal,_suppressClientMessages,
        _callingFormName,_ledgerJournalEngine,_skipIL_RU,_results_RU,_progressBarHide);

    if (ETGCanadaParameters::find().ETGPaymentAdviceEmail == NoYes::Yes)
    {
        LedgerJournalTable  ledgerJournal;
        LedgerJournalTrans  ledgerJournalTrans;
        Args                args = new Args();

        if (_tableId == tableNum(LedgerJournalTable))
        {
            ledgerJournal = _record;
        }
        else if (_tableId == tableNum(LedgerJournalTrans))
        {
            ledgerJournalTrans = _record;
            if (ledgerJournalTrans)
            {
                ledgerJournal = ledgerJournalTrans.ledgerJournalTable();
            }
        }

        if (ledgerJournal)
        { 
            LedgerJournalPost::sendPaymentAdviceEmail(ledgerJournal,args);
        }

    }


    if(VendParameters::find().ETGEnableTermoNumberFeature == NoYes::Yes)
    {
        LedgerJournalTrans ledgerJournalTransLocal = LedgerJournalTrans::findRecId(_record.RecId,false);
        CustTrans custTrans;
        VendTrans vendTrans;

        if(ledgerJournalTransLocal.AccountType == LedgerJournalACType::Cust)
        {
            ttsbegin;
            select forUpdate custTrans
                where custTrans.Voucher == ledgerJournalTransLocal.Voucher;

            custTrans.ETGTERMONumber = ledgerJournalTransLocal.ETGTERMONumber;
            custTrans.ETGMotherTERMOReference = ledgerJournalTransLocal.ETGMotherTERMONumber;
            custTrans.update();
            ttscommit;
        }


        if(ledgerJournalTransLocal.AccountType == LedgerJournalACType::Vend)
        {
            ttsbegin;
            select forUpdate vendTrans
                where vendTrans.Voucher == ledgerJournalTransLocal.Voucher;

            vendTrans.ETGTERMONumber = ledgerJournalTransLocal.ETGTERMONumber;
            vendTrans.ETGMotherTERMOReference = ledgerJournalTransLocal.ETGMotherTERMONumber;
            vendTrans.update();
            ttscommit;
        }
    }


}

private static void sendPaymentAdviceEmail(LedgerJournalTable _journal, Args _args)
{
    LedgerJournalTrans          ledgerJournalTrans;
    BankPaymAdviceContract contract = new BankPaymAdviceContract();
    BankPaymAdviceVendControllerV2 controller = new BankPaymAdviceVendControllerV2();
    SRSPrintDestinationSettings settings;

    controller.parmReportName(ssrsReportStr(BankPaymAdviceVendV2, Report));
    controller.parmShowDialog(false);

    select firstonly ledgerJournalTrans
        where ledgerJournalTrans.JournalNum == _journal.JournalNum;

    _args.record(ledgerJournalTrans);
    controller.parmArgs(_args);
    contract.parmLedgerJournalId(_journal.JournalNum);
    contract.parmAccountNum(ledgerJournalTrans.PaymMode);

    VendTable vendTable = VendTable::findByCompany(ledgerJournalTrans.Company, ledgerJournalTrans.parmAccount());

    contract.parmAccountNum(vendTable.AccountNum);
    contract.parmPaymentStatus(ledgerJournalTrans.PaymentStatus);
    contract.parmCompanyBankAccountId(ledgerJournalTrans.parmOffsetAccount());
    contract.parmLedgerJournalTransRecId(ledgerJournalTrans.RecId);
    contract.parmShouldDefaultFromPrintMgmt(NoYes::Yes);
    controller.parmReportContract().parmRdpContract(contract);

    controller.startOperation();

}

//CS Rajat Dubey 09/05/2025
public static void simulatePost(
    Common  _record,
    TableId _tableId,
    NoYes _transferErrors,
    boolean _splitLargeJournal,
    boolean _suppressClientMessages,
    str _callingFormName,
    LedgerJournalEngine _ledgerJournalEngine,
    boolean _skipIL_RU,
    LedgerJournalCheckPostResults _results_RU,
    boolean _progressBarHide)
{
    if(ETGACFParameters::find().MainAccountForGeneralJournal)
    {
        LedgerJournalTable      ledgerJournal;
        LedgerJournalTrans      ledgerJournalTrans,ledgerJournalTransLoc;
        MainAccountNum          ledgerMainAccountId, offsetMainAccountId;
        str                     mainAccountId = ETGACFParameters::find().MainAccountForGeneralJournal;
        int                     i = 0,j = 0;

        if(_tableId == tableNum(LedgerJournalTable))
        {
            ledgerJournal = _record;
        }
        else if(_tableId == tableNum(LedgerJournalTrans))
        {
            ledgerJournalTrans = _record;
            if(ledgerJournalTrans)
            {
                ledgerJournal = ledgerJournalTrans.ledgerJournalTable();
            }
        }
        while select * from ledgerJournalTransLoc
            where ledgerJournalTransLoc.JournalNum == ledgerJournal.JournalNum
        {
            ledgerMainAccountId = LedgerDimensionFacade::getMainAccountFromLedgerDimension(ledgerJournalTransLoc.LedgerDimension).MainAccountId;
            offsetMainAccountId = LedgerDimensionFacade::getMainAccountFromLedgerDimension(ledgerJournalTransLoc.OffsetLedgerDimension).MainAccountId;
            i = strScan(mainAccountId,ledgerMainAccountId,1,strLen(mainAccountId));
            j = strScan(mainAccountId,offsetMainAccountId,1,strLen(mainAccountId));

            if(i>0||j>0)
            {
                throw error(strFmt("@ETG_New:ManualJournalNotPermittedForMainAccount", ledgerJournalTransLoc.LineNum,ledgerJournalTransLoc.Voucher,ledgerMainAccountId,offsetMainAccountId));
            }
        }
    }

    next simulatePost(_record,_tableId,_transferErrors,_splitLargeJournal,_suppressClientMessages,
        _callingFormName,_ledgerJournalEngine,_skipIL_RU,_results_RU,_progressBarHide);
}
